import{c as e,Q as i,j as t,m as a}from"./chunks/framework.cL5ZtNug.js";const u=JSON.parse('{"title":"Environment Setup","description":"","frontmatter":{},"headers":[],"relativePath":"curriculum/01-environment-setup.md","filePath":"curriculum/01-environment-setup.md"}'),o={name:"curriculum/01-environment-setup.md"};function n(l,s,r,d,h,p){return i(),t("div",null,[...s[0]||(s[0]=[a(`<h1 id="environment-setup" tabindex="-1">Environment Setup <a class="header-anchor" href="#environment-setup" aria-label="Permalink to &quot;Environment Setup&quot;">​</a></h1><p>Get your computer ready for FRC programming.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>Java 17</strong> (required by WPILib)</li><li><strong>VSCode</strong> with WPILib extension</li><li><strong>Git</strong></li></ul><details><summary><strong>What is WPILib?</strong></summary><p><strong>WPILib</strong> (WPI Library) is the official software library for FRC robots. It is maintained by Worcester Polytechnic Institute and provides all the building blocks you need to control a robot: motor control, sensors, communication, and the command-based framework.</p><p><strong>Analogy:</strong> If building a robot were like building a house, WPILib would be the pre-made doors, windows, and plumbing. You could make everything from scratch, but why would you when the basics are already provided?</p><p><strong>What WPILib gives you:</strong></p><ul><li>Motor controller libraries (SparkMax, TalonFX, etc.)</li><li>Sensor libraries (gyros, encoders, cameras)</li><li>Command-based programming framework</li><li>Robot simulation (test without a real robot)</li><li>Dashboard tools (SmartDashboard, Shuffleboard)</li></ul></details><details><summary><strong>What is VSCode and why do we use it?</strong></summary><p><strong>VSCode</strong> (Visual Studio Code) is a free code editor made by Microsoft. It is the official editor for FRC because WPILib provides a VSCode extension that integrates everything you need.</p><p><strong>Why VSCode over other editors:</strong></p><ul><li>Free and works on Windows, macOS, and Linux</li><li>WPILib extension provides one-click build, deploy, and test</li><li>Built-in terminal for running commands</li><li>Git integration for version control</li><li>IntelliSense (autocomplete) for Java code</li></ul><p><strong>Do not use:</strong> IntelliJ, Eclipse, or Notepad for FRC. The WPILib extension only works with VSCode.</p></details><h2 id="install-wpilib" tabindex="-1">Install WPILib <a class="header-anchor" href="#install-wpilib" aria-label="Permalink to &quot;Install WPILib&quot;">​</a></h2><p>Download the installer from <a href="https://github.com/wpilibsuite/allwpilib/releases" target="_blank" rel="noreferrer">GitHub Releases</a>.</p><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><ol><li>Run the <code>.exe</code> installer</li><li>Select <strong>&quot;Install VSCode + WPILib&quot;</strong></li><li>Follow the prompts</li></ol><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><ol><li>Run the <code>.dmg</code> file</li><li>Drag VSCode to Applications</li><li>If blocked, go to <strong>System Settings &gt; Privacy &amp; Security</strong> and click <strong>&quot;Open Anyway&quot;</strong></li></ol><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><ol><li>Extract the <code>.zip</code> installer</li><li>Run the install script:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./Install-WPILib.sh</span></span></code></pre></div></li></ol><details><summary><strong>Why does macOS block the installer?</strong></summary><p>macOS has a security feature called <strong>Gatekeeper</strong> that blocks apps not downloaded from the App Store or identified developers. WPILib is safe, but Apple does not know that.</p><p><strong>What to do:</strong></p><ol><li>Try to open the app normally (it will be blocked)</li><li>Go to <strong>System Settings &gt; Privacy &amp; Security</strong></li><li>Scroll down and click <strong>&quot;Open Anyway&quot;</strong></li><li>Confirm you want to open it</li></ol><p>This is normal for many developer tools on macOS.</p></details><h2 id="verify-installation" tabindex="-1">Verify Installation <a class="header-anchor" href="#verify-installation" aria-label="Permalink to &quot;Verify Installation&quot;">​</a></h2><ol><li>Open VSCode</li><li>Press <code>Ctrl+Shift+P</code> (Windows/Linux) or <code>Cmd+Shift+P</code> (Mac)</li><li>Type <strong>&quot;WPILib&quot;</strong> - you should see WPILib commands appear</li></ol><details><summary><strong>What is the Command Palette?</strong></summary><p>The <strong>Command Palette</strong> (opened with <code>Ctrl+Shift+P</code> or <code>Cmd+Shift+P</code>) is VSCode&#39;s universal search bar for commands. Instead of clicking through menus, you type what you want to do.</p><p><strong>Analogy:</strong> Think of it like Siri or Google Assistant for VSCode. Instead of navigating through settings, you just tell it what you want.</p><p><strong>Useful commands you will use:</strong></p><ul><li><code>WPILib: Build Robot Code</code> - compiles your code</li><li><code>WPILib: Deploy Robot Code</code> - sends code to the robot</li><li><code>WPILib: Start Tool</code> - opens Shuffleboard, SmartDashboard, etc.</li><li><code>WPILib: Create a new project</code> - starts a new robot project</li></ul></details><h2 id="clone-xbotedu" tabindex="-1">Clone XbotEdu <a class="header-anchor" href="#clone-xbotedu" aria-label="Permalink to &quot;Clone XbotEdu&quot;">​</a></h2><p>XbotEdu is the practice repo with unit tests. You can code without a physical robot.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/Team488/XbotEdu.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XbotEdu</span></span></code></pre></div><details><summary><strong>What does &quot;clone&quot; mean?</strong></summary><p><strong>Cloning</strong> downloads a complete copy of a GitHub repository to your computer, including all files and the entire history of changes.</p><p><strong>Analogy:</strong> Think of cloning like making a photocopy of a shared notebook. You get your own copy to write in, and the original on GitHub stays unchanged. When you are done, you can send your changes back to the original (that is called a Pull Request).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub (original)  ----clone----&gt;  Your computer (copy)</span></span></code></pre></div><p>After cloning, you will have a folder on your computer with all the project files.</p></details><h2 id="build-the-project" tabindex="-1">Build the Project <a class="header-anchor" href="#build-the-project" aria-label="Permalink to &quot;Build the Project&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gradlew.bat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS / Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><details><summary><strong>What is Gradle and what does &quot;build&quot; do?</strong></summary><p><strong>Gradle</strong> is a build tool that takes your Java source code and turns it into a program the roboRIO can run.</p><p><strong>What happens when you run <code>build</code>:</strong></p><ol><li>Gradle downloads all dependencies (libraries your code uses)</li><li>Compiles your <code>.java</code> files into <code>.class</code> files (bytecode)</li><li>Runs any tests</li><li>Packages everything into a deployable format</li></ol><p><strong>Analogy:</strong> Think of Gradle like a chef following a recipe. Your Java code is the recipe ingredients, and Gradle follows the instructions (<code>build.gradle</code>) to cook everything together into a finished dish.</p><p><strong>First build takes longer</strong> because Gradle needs to download all the dependencies. Subsequent builds are faster.</p></details><h2 id="run-tests" tabindex="-1">Run Tests <a class="header-anchor" href="#run-tests" aria-label="Permalink to &quot;Run Tests&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gradlew.bat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS / Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><p>You should see test results in the terminal. If all tests pass, you are ready.</p><details><summary><strong>What are unit tests and why do we need them?</strong></summary><p><strong>Unit tests</strong> are small programs that test individual pieces of your code to make sure they work correctly.</p><p><strong>Analogy:</strong> Before a chef serves a dish, they taste it to make sure it is right. Unit tests are like tasting each ingredient separately before combining them.</p><p><strong>Why XbotEdu uses tests:</strong></p><ul><li>You do not need a physical robot to practice</li><li>Tests catch bugs before you deploy to the real robot</li><li>They show you what the correct behavior should be</li><li>Mentors can review your work automatically</li></ul><p><strong>Example:</strong></p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// This test checks that add() returns the correct result</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Test</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> testAddition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    assertEquals</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, calculator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Should pass</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    assertEquals</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, calculator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Should FAIL - catches a bug!</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></details><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td><code>./gradlew: Permission denied</code></td><td>Run <code>chmod +x gradlew</code></td></tr><tr><td>Java version error</td><td>Install Java 17 from <a href="https://adoptium.net/" target="_blank" rel="noreferrer">Adoptium</a></td></tr><tr><td>VSCode does not show WPILib</td><td>Reinstall the WPILib extension from the marketplace</td></tr><tr><td>Build fails on first run</td><td>Wait for dependencies to download, then try again</td></tr></tbody></table><details><summary><strong>What does \`chmod +x\` do?</strong></summary><p><code>chmod +x</code> makes a file <strong>executable</strong> on macOS and Linux. Windows does not need this.</p><p><strong>Why it is needed:</strong> The <code>gradlew</code> script is a program that runs Gradle. By default, downloaded files are not allowed to run as programs for security reasons. <code>chmod +x</code> tells the system &quot;this file is safe to run as a program.&quot;</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gradlew</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Make gradlew executable</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Now it will work</span></span></code></pre></div><p>The <code>+x</code> means &quot;add execute permission.&quot;</p></details><hr><h2 id="quiz" tabindex="-1">Quiz <a class="header-anchor" href="#quiz" aria-label="Permalink to &quot;Quiz&quot;">​</a></h2><p><strong>Q1:</strong> Which Java version does WPILib require?</p><ul><li>[ ] A) Java 11</li><li>[ ] B) Java 17</li><li>[ ] C) Java 21</li><li>[ ] D) Java 8</li></ul><details><summary>Answer</summary><p><strong>B) Java 17</strong></p><p><strong>Why:</strong> WPILib is built against Java 17, which is a Long Term Support (LTS) release. This means it receives security updates for several years. Java 11 is too old and lacks features WPILib uses. Java 21 is newer but WPILib has not been updated to support it yet. Java 8 is very outdated and missing many modern Java features.</p></details><p><strong>Q2:</strong> What command builds the project on macOS/Linux?</p><ul><li>[ ] A) <code>gradle build</code></li><li>[ ] B) <code>./gradlew build</code></li><li>[ ] C) <code>make build</code></li><li>[ ] D) <code>npm build</code></li></ul><details><summary>Answer</summary><p><strong>B) <code>./gradlew build</code></strong></p><p><strong>Why:</strong> <code>gradlew</code> (Gradle Wrapper) is a script included in the project that downloads and runs the correct version of Gradle. The <code>./</code> prefix means &quot;run the file in the current directory.&quot; Option A (<code>gradle build</code>) would use a globally installed Gradle which might be the wrong version. Option C (<code>make</code>) is a different build system used for C/C++ projects. Option D (<code>npm</code>) is for JavaScript/Node.js projects, not Java.</p></details><p><strong>Q3:</strong> Why does XbotEdu use unit tests?</p><ul><li>[ ] A) To slow down development</li><li>[ ] B) So you can practice without a physical robot</li><li>[ ] C) To replace the driver station</li><li>[ ] D) To generate robot logs</li></ul><details><summary>Answer</summary><p><strong>B) So you can practice without a physical robot</strong></p><p><strong>Why:</strong> Unit tests simulate robot behavior on your computer, so you can write and test code even when you do not have access to the physical robot. This is especially useful during off-season or when working from home. Option A is the opposite of the truth -- tests actually speed up development by catching bugs early. Options C and D are unrelated to what unit tests do.</p></details>`,43)])])}const g=e(o,[["render",n]]);export{u as __pageData,g as default};
